import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

function HomePage() {
  const [videos, setVideos] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios.get('http://localhost:8000/api/videos/')
      .then(response => {
        setVideos(response.data);
        setLoading(false);
      })
      .catch(error => {
        console.error('Ошибка загрузки видео:', error);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return (
      <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '60vh' }}>
        <div style={{ textAlign: 'center', color: 'white' }}>
          <div style={{ fontSize: 48, marginBottom: 16 }}>🎬</div>
          <p>Загрузка видео...</p>
        </div>
      </div>
    );
  }

  return (
    <div style={{ maxWidth: 1400, margin: '0 auto' }}>
      {/* НОВЫЙ БЛОК ПРИВЕТСТВИЯ */}
      <div style={{
        textAlign: 'center',
        padding: '60px 32px',
        marginBottom: 48,
        background: 'rgba(255,255,255,0.95)',
        borderRadius: 30,
        backdropFilter: 'blur(10px)',
        boxShadow: '0 20px 40px rgba(0,0,0,0.1)'
      }}>
        <div style={{ fontSize: 64, marginBottom: 20 }}>🎬✨</div>
        <h1 style={{
          fontSize: 'clamp(36px, 6vw, 56px)',
          fontWeight: 800,
          marginBottom: 16,
          background: 'linear-gradient(135deg, #667eea 0%, #764ba2 50%, #f093fb 100%)',
          WebkitBackgroundClip: 'text',
          WebkitTextFillColor: 'transparent',
          backgroundClip: 'text'
        }}>
          Добро пожаловать в CineFlow
        </h1>
        <p style={{
          fontSize: 'clamp(16px, 2vw, 20px)',
          color: '#4a5568',
          maxWidth: 600,
          margin: '0 auto 32px',
          lineHeight: 1.6
        }}>
          Откройте для себя мир удивительных видео. Загружайте свои работы, 
          делитесь впечатлениями и вдохновляйтесь вместе с нами.
        </p>
        <div style={{ display: 'flex', gap: 16, justifyContent: 'center', flexWrap: 'wrap' }}>
          <Link to="/upload" className="btn-primary" style={{ textDecoration: 'none' }}>
            🚀 Загрузить видео
          </Link>
          <Link to="/register" style={{
            background: 'transparent',
            color: '#667eea',
            border: '2px solid #667eea',
            padding: '12px 28px',
            borderRadius: 30,
            textDecoration: 'none',
            fontWeight: 600,
            transition: 'all 0.3s ease'
          }}>
            📝 Регистрация
          </Link>
        </div>
      </div>

      {/* Сетка видео */}
      {videos.length === 0 ? (
        <div style={{
          textAlign: 'center',
          padding: 64,
          background: 'rgba(255,255,255,0.95)',
          borderRadius: 24,
          backdropFilter: 'blur(10px)'
        }}>
          <div style={{ fontSize: 64, marginBottom: 20 }}>📭</div>
          <p style={{ fontSize: 18, marginBottom: 24 }}>Пока нет видео</p>
          <Link to="/upload" className="btn-primary">
            + Загрузить первое видео
          </Link>
        </div>
      ) : (
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fill, minmax(320px, 1fr))',
          gap: 28
        }}>
          {videos.map(video => (
            <Link to={`/video/${video.id}`} key={video.id} style={{ textDecoration: 'none' }}>
              <div style={{
                background: 'rgba(255,255,255,0.95)',
                borderRadius: 20,
                overflow: 'hidden',
                backdropFilter: 'blur(10px)',
                transition: 'transform 0.3s ease, box-shadow 0.3s ease',
                cursor: 'pointer',
                boxShadow: '0 8px 20px rgba(0,0,0,0.1)'
              }}
              onMouseEnter={(e) => {
                e.currentTarget.style.transform = 'translateY(-8px)';
                e.currentTarget.style.boxShadow = '0 20px 40px rgba(0,0,0,0.2)';
              }}
              onMouseLeave={(e) => {
                e.currentTarget.style.transform = 'translateY(0)';
                e.currentTarget.style.boxShadow = '0 8px 20px rgba(0,0,0,0.1)';
              }}>
                
                {/* Превью */}
                <div style={{
                  width: '100%',
                  aspectRatio: '16/9',
                  background: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: 48,
                  color: 'white'
                }}>
                  🎬
                </div>
                
                {/* Информация */}
                <div style={{ padding: '16px 20px' }}>
                  <h3 style={{
                    fontSize: 16,
                    fontWeight: 700,
                    color: '#1a1a1a',
                    marginBottom: 8,
                    display: '-webkit-box',
                    WebkitLineClamp: 2,
                    WebkitBoxOrient: 'vertical',
                    overflow: 'hidden'
                  }}>
                    {video.title}
                  </h3>
                  <p style={{ fontSize: 13, color: '#6c757d', margin: 0 }}>
                    {video.uploaded_by_name || 'Аноним'} • {video.views || 0} просмотров
                  </p>
                </div>
              </div>
            </Link>
          ))}
        </div>
      )}
    </div>
  );
}

export default HomePage;ы
